_AVAILABLE_XML_BYTES = b"<Legislation>" + (b"x" * 128) + b"</Legislation>"


def _required_payload(op: LegalOperation) -> IRNode:
    assert op.payload is not None
    return op.payload


def _required_text_patch(op: LegalOperation) -> TextPatchSpec:
    assert op.text_patch is not None
    return op.text_patch


def _required_text_patch_replacement(op: LegalOperation) -> str:
    replacement = _required_text_patch(op).replacement
    assert replacement is not None
    return replacement


def _required_fragment_substitution(op: LegalOperation) -> list[dict[str, Any]]:
    fragment = _fragment_substitution(op)
    assert fragment is not None
    return fragment


def test_instruction_text_before_amendment_container_is_cached_by_source_element() -> None:
    element = ET.fromstring(
        """
        <P1>
          <Text>In section 1, after subsection (1) insert-</Text>
          <BlockAmendment><P2><Text>payload</Text></P2></BlockAmendment>
          <Text>tail ignored</Text>
        </P1>
        """
    )

    _INSTRUCTION_TEXT_CACHE.pop(element, None)
    assert _instruction_text_before_amendment_container(element) == "In section 1, after subsection (1) insert-"
    assert _INSTRUCTION_TEXT_CACHE[element] == "In section 1, after subsection (1) insert-"
    assert _instruction_text_before_amendment_container(element) == "In section 1, after subsection (1) insert-"


def test_get_id_sequence_preserves_hyphen_underscore_boundaries() -> None:
    assert _get_id_sequence("ukpga-1988_1-section_12A") == (
        "ukpga",
        "1988",
        "1",
        "section",
        "12",
        "a",
    )
    assert _get_id_sequence("part__iv--paragraph_3b") == (
        "part",
        "4",
        "paragraph",
        "3",
        "b",
    )


def test_first_component_matches_preserves_document_order_with_number_index() -> None:
    root = ET.fromstring(
        """
        <Body>
          <P1><Pnumber>7</Pnumber><Text>first section-like node</Text></P1>
          <P2><Pnumber>7</Pnumber><Text>wrong kind</Text></P2>
          <Section><Number>7</Number><Text>second section-like node</Text></Section>
          <P1group><Pnumber>7</Pnumber><Text>third section-like node</Text></P1group>
        </Body>
        """
    )

    matches = _first_component_matches(root, "section", "7")

    assert [element.tag for element in matches] == ["P1", "Section", "P1group"]
    assert [" ".join(element.itertext()).strip() for element in matches] == [  # type: ignore[arg-type]  # ty: ignore[no-matching-overload]
        "7 first section-like node",
        "7 second section-like node",
        "7 third section-like node",
    ]


def replay_uk_ops(base, ops, **kwargs):
    return UKReplayPipeline(Path(".")).apply_ops(base, ops, **kwargs)


def _replace_patch(match: str, replacement: str, occurrence: int = 0) -> TextPatchSpec:
    return TextPatchSpec(
        kind=TextPatchKindEnum.REPLACE,
        selector=TextSelector(match_text=match, occurrence=occurrence),
        replacement=replacement,
    )


def _append_patch(insertion: str) -> TextPatchSpec:
    return TextPatchSpec(
        kind=TextPatchKindEnum.APPEND,
        selector=TextSelector(match_text="TEXT_END", occurrence=0),
        replacement=insertion,
    )


def test_replay_words_in_brackets_replaces_unique_parenthesized_span() -> None:
    op = LegalOperation(
        op_id="uk_test_words_in_brackets_replay",
        sequence=0,
        action=StructuralAction.TEXT_REPLACE,
        target=LegalAddress(path=(("section", "100"), ("subsection", "6"))),
        text_patch=_replace_patch("TEXT_IN_BRACKETS", "(including a nil liability)"),
    )
    base = IRStatute(
        statute_id="ukpga/2016/24",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="100",
                    attrs={"eId": "section-100"},
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="6",
                            attrs={"eId": "section-100-6"},
                            text="A reference to liability (under section 6) is included.",
                        ),
                    ),
                ),
            ),
        ),
    )
    adjudications: list[CompileAdjudication] = []
    executor: Any = UKReplayExecutor(base, adjudications_out=adjudications)

    executor.apply_op(op)

    subsection = executor.statute.body.children[0].children[0]
    assert subsection.text == "A reference to liability (including a nil liability) is included."
    assert len(adjudications) == 1
    assert adjudications[0].kind == "uk_replay_words_in_brackets_text_rewrite_applied"
    assert adjudications[0].detail["source_shape"] == "words_in_brackets_selector"


