        affected_class="UnitedKingdomPublicGeneralAct",
        affected_year="1996",
        affected_number="61",
        affected_provisions="Sch. 14",
        affecting_uri="/id/uksi/1999/416",
        affecting_class="UnitedKingdomStatutoryInstrument",
