def test_source_after_definition_insert_term_is_bounded_on_quote_heavy_text() -> None:
    from lawvm.uk_legislation.source_definition_fragments import (
        _looks_like_definition_entry_payload,
        _source_after_definition_insert_term,
    )

    hostile = (
        " ".join(
            f"after the definition of “term {index}” " + ("x " * 80)
            for index in range(300)
        )
        + " after the definition of “final term”, there is inserted—"
    )

    assert _source_after_definition_insert_term(hostile) == "final term"
    assert _looks_like_definition_entry_payload(
        hostile + " “bounded definition” means a bounded test definition;"
    )


def test_appropriate_place_definition_entry_instruction_strip_is_bounded() -> None:
    from lawvm.uk_legislation.source_definition_fragments import (
        _strip_appropriate_place_definition_entry_instruction,
    )

    assert _strip_appropriate_place_definition_entry_instruction(
        "iii at the appropriate place insert— “operational service standard” "
        "is to be construed in accordance with section 3C(1)(b), ,"
    ) == (
        "“operational service standard” is to be construed in accordance with section 3C(1)(b), ,"
    )
    assert _strip_appropriate_place_definition_entry_instruction(
        "2 b at the appropriate place inserted- “scheme” means the test scheme;"
    ) == "“scheme” means the test scheme;"
    assert _strip_appropriate_place_definition_entry_instruction(
        "after the definition of “scheme” insert— “operator” means an operator;"
    ) is None


def test_source_carried_following_words_repeal_instruction_scan() -> None:
    from lawvm.uk_legislation.source_definition_fragments import (
        _has_following_words_repeal_instruction,
    )

    assert _has_following_words_repeal_instruction(
        "in subsection (2), the following words are repealed—"
    )
    assert _has_following_words_repeal_instruction(
        "in subsection (2), following word omitted—"
    )
    assert not _has_following_words_repeal_instruction(
        "in subsection (2), after the following words insert—"
    )
    assert not _has_following_words_repeal_instruction(
        "in subsection (2), the following wording is omitted—"
    )


def test_compile_source_carried_following_words_repeal_from_block_payload() -> None:
    source_root = ET.fromstring(
        f"""
        <Legislation xmlns="{_LEG_NS}">
          <Body>
            <P2 id="schedule-paragraph-3-9">
              <Pnumber>9</Pnumber>
              <P2para>
                <P3 id="schedule-paragraph-3-9-b">
                  <Pnumber>b</Pnumber>
                  <P3para>
                    <Text>in subsection (2), the following words are repealed—</Text>
                    <BlockAmendment>
                      <P3para>
                        <Text>section 3(3)(a); section 6(2)(a) and (4)(a); section 8(1) and (2);</Text>
                      </P3para>
                    </BlockAmendment>
                  </P3para>
                </P3>
              </P2para>
            </P2>
          </Body>
        </Legislation>
        """
    )
    extracted_el = source_root.find(f".//{{{_LEG_NS}}}BlockAmendment")
    assert extracted_el is not None
    effect = UKEffectRecord(
        effect_id="key-source-carried-following-words-repeal",
        effect_type="words repealed",
        applied=True,
        requires_applied=True,
        modified="2023-12-04",
        affected_uri="/id/asp/2001/2/section/82/subsection/2",
        affected_class="ScottishAct",
        affected_year="2001",
        affected_number="2",
        affected_provisions="s. 82(2)",
        affecting_uri="/id/asp/2019/17",
        affecting_class="ScottishAct",
        affecting_year="2019",
        affecting_number="17",
        affecting_provisions="sch. para. 3(9)(b)",
        affecting_title="Transport (Scotland) Act 2019",
        in_force_dates=[{"date": "2023-12-04", "prospective": "false"}],
    )
    observations: list[dict[str, Any]] = []

    ops = compile_effect_to_ir_ops(
        effect,
        extracted_el,
        sequence=0,
        lowering_rejections_out=observations,
        source_root=source_root,
    )

    assert len(ops) == 1
    assert ops[0].action is StructuralAction.TEXT_REPEAL
    assert ops[0].target.path == (("section", "82"), ("subsection", "2"))
    assert ops[0].text_patch is not None
    assert ops[0].text_patch.selector.match_text == (
        "section 3(3)(a); section 6(2)(a) and (4)(a); section 8(1) and (2);"
    )
    assert ops[0].text_patch.replacement is None
    assert (
        f"{_NOTE_TEXT_REWRITE_RULE}uk_effect_source_carried_following_words_repeal_text_patch"
        in ops[0].provenance_tags
    )
    assert [record["rule_id"] for record in observations] == [
        "uk_effect_source_carried_following_words_repeal_text_patch"
    ]
    base = IRStatute(
        statute_id="asp/2001/2",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="82",
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="2",
                            text=(
                                "Where references apply— section 3(3)(a);\n\n"
                                "section 6(2)(a) and (4)(a);\n\n"
                                "section 8(1) and (2); section 33(4);"
                            ),
                        ),
                    ),
                ),
            ),
        ),
    )

    replayed = replay_uk_ops(base, ops)
    subsection = replayed.body.children[0].children[0]

    assert subsection.text == "Where references apply—  section 33(4);"


