def test_executor_bounded_range_text_patch_preserves_node_children_when_own_text_matches() -> None:
    adjudications: list[CompileAdjudication] = []
    statute = IRStatute(
        statute_id="asp/2001/14",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="3",
                    attrs={"eId": "section-3"},
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="1",
                            text="A police authority may obtain any record formerly recalled.",
                            attrs={"eId": "section-3-1"},
                            children=(
                                IRNode(kind=IRNodeKind.PARAGRAPH, label="a", text="first limb"),
                                IRNode(kind=IRNodeKind.PARAGRAPH, label="b", text="second limb"),
                            ),
                        ),
                    ),
                ),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute, adjudications_out=adjudications)
    op = LegalOperation(
        op_id="uk_test_node_local_range_patch_preserves_children",
        sequence=0,
        action=StructuralAction.TEXT_REPLACE,
        target=LegalAddress(path=(("section", "3"), ("subsection", "1"))),
        text_patch=TextPatchSpec(
            kind=TextPatchKindEnum.REPLACE,
            selector=TextSelector(match_text="TEXT_FROM_any_TO_recalled", occurrence=1),
            replacement="the Police Service of Scotland",
        ),
    )

    executor.apply_op(op)

    subsection = executor.statute.body.children[0].children[0]
    assert subsection.text == (
        "A police authority may obtain the Police Service of Scotland."
    )
    assert [child.label for child in subsection.children] == ["a", "b"]
    assert [child.text for child in subsection.children] == ["first limb", "second limb"]
    assert [row.kind for row in adjudications] == [
        "uk_replay_text_range_anchor_word_boundary_normalized",
        "uk_replay_node_local_range_text_rewrite_applied",
    ]
    assert adjudications[1].detail["blocking"] is False
    assert adjudications[1].detail["strict_disposition"] == "record"
    assert adjudications[1].detail["source_shape"] == "node_local_range_selector"


def test_executor_exact_eid_lookup_index_tracks_structural_mutations() -> None:
    statute = IRStatute(
        statute_id="ukpga/2001/1",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="1",
                    attrs={"eId": "section-1"},
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="1",
                            text="old one",
                            attrs={"eId": "section-1-1"},
                        ),
                    ),
                ),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute)

    node, parent, idx = executor._find_node_and_parent_statute("section-1-1")
    assert node is not None
    assert parent is not None
    assert idx == 0
    assert executor._eid_lookup_index is not None
    assert executor._eid_lookup_index["section-1-1"][0] is node

    insert_op = LegalOperation(
        op_id="uk_test_insert_index_update",
        sequence=1,
        action=StructuralAction.INSERT,
        target=LegalAddress(path=(("section", "1"), ("subsection", "2"))),
        payload=IRNode(kind=IRNodeKind.SUBSECTION, label="2", text="new two"),
    )
    executor.apply_op(insert_op)

    inserted, inserted_parent, inserted_idx = executor._find_node_and_parent_statute("section-1-2")
    assert inserted is not None
    assert inserted_parent is executor.statute.body.children[0]
    assert inserted_idx == 1
    assert executor._eid_lookup_index is not None
    assert executor._eid_lookup_index["section-1-2"][0] is inserted

    replace_op = LegalOperation(
        op_id="uk_test_replace_index_update",
        sequence=2,
        action=StructuralAction.REPLACE,
        target=LegalAddress(path=(("section", "1"), ("subsection", "2"))),
        payload=IRNode(kind=IRNodeKind.SUBSECTION, label="2", text="replaced two"),
    )
    executor.apply_op(replace_op)

    replaced, _, _ = executor._find_node_and_parent_statute("section-1-2")
    assert replaced is not None
    assert replaced is not inserted
    assert replaced.text == "replaced two"
    assert executor._eid_lookup_index is not None
    assert executor._eid_lookup_index["section-1-2"][0] is replaced

    repeal_op = LegalOperation(
        op_id="uk_test_repeal_index_update",
        sequence=3,
        action=StructuralAction.REPEAL,
        target=LegalAddress(path=(("section", "1"), ("subsection", "1"))),
    )
    executor.apply_op(repeal_op)

    removed, _, _ = executor._find_node_and_parent_statute("section-1-1")
    assert removed is None
    assert executor._eid_lookup_index is not None
    assert "section-1-1" not in executor._eid_lookup_index


def test_executor_eid_suffix_lookup_uses_scoped_unique_alias(monkeypatch: pytest.MonkeyPatch) -> None:
    statute = IRStatute(
        statute_id="ukpga/2001/1",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="1",
                    attrs={"eId": "section-1"},
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="2",
                            text="target",
                            attrs={"eId": "prefix-section-1-2"},
                        ),
                    ),
                ),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute)

    def fail_recursive_search(*_args: object, **_kwargs: object) -> None:
        raise AssertionError("unique suffix alias should resolve from the eId index")

    monkeypatch.setattr(executor, "_find_node_and_parent", fail_recursive_search)
    node, parent, idx = executor._find_node_and_parent_statute("section-1-2")

    assert node is not None
    assert node.text == "target"
    assert parent is executor.statute.body.children[0]
    assert idx == 0


