def test_parse_table_cell_ordered_list_units_preserves_evidence_without_text_duplication() -> None:
    xml = f"""
    <Legislation xmlns="{_LEG_NS}">
      <Body>
        <P1 id="section-132">
          <Pnumber>132</Pnumber>
          <P2 id="section-132-1">
            <Pnumber>1</Pnumber>
            <P2para>
              <Text>Intro.</Text>
              <Tabular>
                <table xmlns="http://www.w3.org/1999/xhtml">
                  <tbody>
                    <tr>
                      <td>1</td>
                      <td>punishment</td>
                      <td>
                        <Para xmlns="{_LEG_NS}">
                          <Text>only if—</Text>
                          <OrderedList Type="alpha" Decoration="parens">
                            <ListItem NumberOverride="a"><Para><Text>leading rate;</Text></Para></ListItem>
                            <ListItem NumberOverride="b"><Para><Text>lance corporal;</Text></Para></ListItem>
                          </OrderedList>
                        </Para>
                      </td>
                    </tr>
                  </tbody>
                </table>
              </Tabular>
            </P2para>
          </P2>
        </P1>
      </Body>
    </Legislation>
    """.encode()

    statute = parse_uk_statute_ir_bytes(xml, statute_id="ukpga/2006/52")

    cell = statute.body.children[0].children[0].children[0].children[0].children[2]
    assert " ".join(cell.text.split()) == "only if— leading rate; lance corporal;"
    assert cell.children == ()
    assert cell.attrs["source_rule_id"] == "uk_table_cell_ordered_list_units_preserved"
    assert json.loads(cell.attrs["source_ordered_list_units_json"]) == [
        {
            "source_list_type": "alpha",
            "source_list_decoration": "parens",
            "label": "a",
            "text": "leading rate;",
        },
        {
            "source_list_type": "alpha",
            "source_list_decoration": "parens",
            "label": "b",
            "text": "lance corporal;",
        },
    ]


def test_compile_embedded_table_structural_paragraph_substitution_is_not_table_entry_rejected() -> None:
    extracted_el = ET.fromstring(
        f"""
        <P1 xmlns="{_LEG_NS}" id="section-127">
          <Pnumber>127</Pnumber>
          <P1para>
            <Text>In Schedule 21 to the Sentencing Code, for paragraph 6 substitute—</Text>
            <BlockAmendment>
              <P1>
                <Pnumber>5A</Pnumber>
                <P1para>
                  <Text>This paragraph applies if—</Text>
                  <P2><Pnumber>2</Pnumber><P2para><Text>The appropriate starting point is the period given in the entry in column 2, 3 or 4 of the following table.</Text></P2para></P2>
                  <Tabular>
                    <table>
                      <tbody>
                        <tr><td>17</td><td>27 years</td><td>23 years</td><td>14 years</td></tr>
                      </tbody>
                    </table>
                  </Tabular>
                </P1para>
              </P1>
              <P1>
                <Pnumber>6</Pnumber>
                <P1para><Text>The appropriate starting point is 12 years.</Text></P1para>
              </P1>
            </BlockAmendment>
          </P1para>
        </P1>
        """
    )
    effect = UKEffectRecord(
        effect_id="uk_test_embedded_table_structural_paragraph_substitution",
        effect_type="substituted for Sch. 21 para. 6",
        applied=True,
        requires_applied=True,
        modified="2022-06-28",
        affected_uri="/id/ukpga/2020/17/schedule/21/paragraph/5A",
        affected_class="UnitedKingdomPublicGeneralAct",
        affected_year="2020",
        affected_number="17",
        affected_provisions="Sch. 21 para. 5A 6",
        affecting_uri="/id/ukpga/2022/32",
        affecting_class="UnitedKingdomPublicGeneralAct",
        affecting_year="2022",
        affecting_number="32",
        affecting_provisions="s. 127",
        affecting_title="Police, Crime, Sentencing and Courts Act 2022",
        in_force_dates=[{"date": "2022-06-28", "prospective": "false"}],
    )
    lowering_rejections: list[dict[str, Any]] = []

    ops = compile_effect_to_ir_ops(
        effect,
        extracted_el,
        sequence=0,
        lowering_rejections_out=lowering_rejections,
    )

    assert [op.action for op in ops] == [StructuralAction.INSERT, StructuralAction.REPLACE]
    assert [str(op.target) for op in ops] == ["schedule:21/paragraph:5a", "schedule:21/paragraph:6"]
    assert [op.payload.label if op.payload is not None else "" for op in ops] == ["5A", "6"]
    assert any(
        row["rule_id"] == "uk_effect_embedded_table_payload_structural_substitution_preserved"
        and row["target_ref"] == "Sch. 21 para. 5A"
        and row["blocking"] is False
        for row in lowering_rejections
    )
    assert any(
        row["rule_id"] == "uk_effect_substituted_series_pre_anchor_sibling_insert_lowered"
        and row["target_ref"] == "Sch. 21 para. 5A"
        and row["blocking"] is False
        for row in lowering_rejections
    )
    assert not any(
        row["rule_id"] == "uk_effect_table_entry_instruction_rejected"
        for row in lowering_rejections
    )


def test_compile_embedded_table_structural_subsection_substitution_is_not_table_entry_rejected() -> None:
    extracted_el = ET.fromstring(
        f"""
        <P2 xmlns="{_LEG_NS}" id="section-13-3">
          <Pnumber>3</Pnumber>
          <P2para>
            <Text>For subsection (1A) substitute—</Text>
            <BlockAmendment>
              <P2>
                <Pnumber>1A</Pnumber>
                <P2para>
                  <Text>
                    In row 1 of the Table, in paragraph (c) of the entry in the
                    third column, in relation to the Royal Air Force Regiment, the
                    reference to a corporal is to be read as a reference to a lance
                    corporal.
                  </Text>
                </P2para>
              </P2>
            </BlockAmendment>
          </P2para>
        </P2>
        """
    )
    effect = UKEffectRecord(
        effect_id="key-bc88f8c99b4586eef703c364c161ead1",
        effect_type="substituted",
        applied=True,
        requires_applied=True,
        modified="2022-05-01",
        affected_uri="/id/ukpga/2006/52/section/132/subsection/1A",
        affected_class="UnitedKingdomPublicGeneralAct",
        affected_year="2006",
        affected_number="52",
        affected_provisions="s. 132(1A)",
        affecting_uri="/id/ukpga/2021/35",
        affecting_class="UnitedKingdomPublicGeneralAct",
        affecting_year="2021",
        affecting_number="35",
        affecting_provisions="s. 13(3)",
        affecting_title="Armed Forces Act 2021",
        in_force_dates=[{"date": "2022-05-01", "prospective": "false"}],
    )
    lowering_rejections: list[dict[str, Any]] = []

    ops = compile_effect_to_ir_ops(
        effect,
        extracted_el,
        sequence=0,
        lowering_rejections_out=lowering_rejections,
    )

    assert len(ops) == 1
    # The widened letter-suffix structural guard now promotes
    # letter-suffix targets to Insert regardless of instruction text. subsection:1a
    # is a letter-suffix label so the op becomes INSERT with the numeric-stem anchor.
    # Replay-time apply will fall back to Replace semantics if the leaf already exists.
    assert ops[0].action is StructuralAction.INSERT
    assert ops[0].target == LegalAddress(path=(("section", "132"), ("subsection", "1a")))
    assert ops[0].payload is not None
    assert ops[0].payload.label == "1A"
    assert any(
        row["rule_id"] == "uk_effect_embedded_table_payload_structural_substitution_preserved"
        and row["source_action"] == "subsection_substitution"
        and row["blocking"] is False
        for row in lowering_rejections
    )
    assert not any(
        row["rule_id"] == "uk_effect_table_entry_instruction_rejected"
        for row in lowering_rejections
    )
    # A16 promotion observation must also be emitted.
    assert any(
        row["rule_id"] == "uk_effect_after_anchor_insert_promoted"
        for row in lowering_rejections
    )


