def test_uk_source_ancestor_chain_caches_repeated_source_walks() -> None:
    # WeakKeyDictionary-backed cache: no cache_clear() needed — each root gets
    # its own entry.  Cache hit is verified by identity equality of the result
    # tuple (same object returned on second call).
    root = ET.fromstring(
        """
        <Legislation>
          <Body>
            <P1group id="section-1">
              <P1 id="section-1-1">Text</P1>
            </P1group>
          </Body>
        </Legislation>
        """
    )
    target = root.find(".//*[@id='section-1-1']")
    assert target is not None

    first = _source_ancestor_chain(root, target)
    second = _source_ancestor_chain(root, target)

    assert first == second
    # Identity check: the same tuple object is returned on cache hit
    assert first is second


def test_uk_source_ancestor_chain_preserves_same_id_fallback() -> None:
    # WeakKeyDictionary-backed cache: no cache_clear() needed.
    root = ET.fromstring(
        """
        <Legislation>
          <Body>
            <P1group id="section-1">
              <P1 id="section-1-1">Text</P1>
            </P1group>
          </Body>
        </Legislation>
        """
    )
    detached_same_id = ET.Element("P1", {"id": "section-1-1"})

    ancestors = _source_ancestor_chain(root, detached_same_id)

    assert [a.tag for a in ancestors] == ["P1group", "Body", "Legislation"]


def test_uk_source_context_caches_repeated_provision_extraction() -> None:
    root = ET.fromstring(
        """
        <Legislation>
          <Body>
            <P1group id="section-1">
              <P1 id="section-1-1">Text</P1>
            </P1group>
          </Body>
        </Legislation>
        """
    )
    target = root.find(".//*[@id='section-1-1']")
    assert target is not None
    calls: list[str] = []

    def extractor(_xml_bytes: bytes, provision_ref: str, **_kwargs: Any) -> ET._Element | None:
        calls.append(provision_ref)
        return target

    context = UKAffectingSourceContext(
        xml_bytes=b"<Legislation />",
        root=root,
        parent_map={},
        exact_id_map={},
        sequence_map={},
        source_status="available",
        source_size=15,
        locator="memory://source",
        authority_layer="AFFECTING_ACT_TEXT",
        provision_extractor=extractor,
    )

    first = _extract_from_affecting_source_context(context, "s. 1")
    second = _extract_from_affecting_source_context(context, "s. 1")

    assert first is target
    assert second is target
    assert calls == ["s. 1"]


